import { getListIndex } from './highlight-item-helpers';

function ScrollItemToView(mouse, data) {
    let manager = this,
        { options } = manager,
        { scrollToItem } = options,
        point = getListIndex(data, options);

    if (!scrollToItem) {
        return;
    }

    let { ulElement, liElement, available, isScrollable, isHorizontal } = scrollToItem,
        scrollType = isHorizontal ? 'scrollLeft' : 'scrollTop',
        offsetType = isHorizontal ? 'offsetLeft' : 'offsetTop';

    // Scroll into view
    if (isScrollable) {
        ulElement[scrollType] = liElement[point][offsetType] - available / 2;
    }
}

export { ScrollItemToView };
